// 記事データを整形する
const items = $input.all();
const seen = new Set();
const formatted = [];

for (const item of items) {
  const link = item.json.link || item.json.url || '';
  if (seen.has(link)) continue;
  seen.add(link);
  formatted.push({
    json: {
      title: item.json.title || 'タイトルなし',
      link: link,
      date: item.json.pubDate || item.json.date || new Date().toISOString(),
      summary: item.json.contentSnippet || item.json.content || item.json.description || '',
      source: item.json.feedUrl || ''
    }
  });
}

return formatted;

// ★ キーワードをここに追加するだけで検索対象が増える！
const keywords = [
  'AI', 'エージェント', 'LLM', 'Claude', 'GPT',
  'GitHub', 'Python', 'n8n', 'Obsidian', '自動化',
  'agent', 'automation', 'machine learning'
];

const items = $input.all();
const filtered = items.filter(item => {
  const text = (
    (item.json.title || '') + ' ' +
    (item.json.summary || '')
  ).toLowerCase();
  return keywords.some(kw => text.includes(kw.toLowerCase()));
});

return filtered.length > 0 ? filtered : items;

// 上位10件だけClaudeに渡す（APIコスト節約）
const items = $input.all();
const top10 = items.slice(0, 10);

const articleList = top10.map((item, i) => {
  return `【記事${i+1}】
タイトル: ${item.json.title}
URL: ${item.json.link}
概要: ${(item.json.summary || '').substring(0, 200)}`;
}).join('\n\n');

const prompt = `あなたは私専属のインテリジェンスアナリストです。

以下の記事を分析してください：

${articleList}

各記事について以下を出力してください：
重要度: A（今日必読）/ B（今週中）/ C（スキップ）
カテゴリ: 業界ニュース/技術/人物動向/競合/論文
要約: 30文字以内
関連技術: （タグ形式）
意外な繋がり: 他の記事や過去のトレンドとの関連

JSON形式で出力してください。`;

return [{ json: { prompt, articles: top10 } }];

// Claudeのレスポンスを取得
const response = $input.first().json;
const claudeText = response.content[0].text;

// articlesは前のノードから取得
const articles = $node["Claude用プロンプト準備"].json.articles || [];
const today = new Date().toISOString().split('T')[0];

// 各記事のMarkdownを生成
const results = articles.map((article) => {
  const title = article.json.title || 'タイトルなし';
  const link = article.json.link || '';
  const summary = (article.json.summary || '').substring(0, 300);
  const source = article.json.source || '';

  const safeTitle = title
    .replace(/[\\/\:*?"<>|]/g, '')
    .substring(0, 40);

  const markdown = `---
title: "${title}"
date: ${today}
importance: 
tags: []
related_people: []
related_companies: []
related_tech: []
source: ${source}
url: ${link}
---

## 📄 要約
${summary}

## 🤖 AI分析
${claudeText}

## 🔗 元記事
${link}

## ⚡ 意外な繋がり
（週次インサイトで自動分析）

## 💡 自分のメモ
`;

  return {
    json: {
      filename: `${today}_${safeTitle}.md`,
      content: markdown,
      title: title,
      link: link,
      claudeAnalysis: claudeText
    }
  };
});

return results;

// ObsidianのVaultに保存
const fs = require('fs');
const path = require('path');

const items = $input.all();
const vaultPath = '/obsidian/00_Inbox';
const savedFiles = [];

for (const item of items) {
  const filename = item.json.filename;
  const content = item.json.content;
  if (!filename || !content) continue;

  const filepath = path.join(vaultPath, filename);
  try {
    fs.writeFileSync(filepath, content, 'utf8');
    savedFiles.push(filename);
  } catch (e) {
    console.error(`保存失敗: ${filename}`, e.message);
  }
}

return [{
  json: {
    saved: savedFiles.length,
    files: savedFiles,
    message: `${savedFiles.length}件をObsidianに保存しました`
  }
}];

// LINE通知用サマリー生成
const result = $input.first().json;
const today = new Date().toISOString().split('T')[0];

const message = `📊 情報収集完了 ${today}

✅ 保存件数: ${result.saved}件

保存ファイル:
${result.files.slice(0, 3).map(f => '・' + f).join('
')}

詳細はObsidianで確認してください`;

return [{ json: { message } }];
